function [symLeft,symImg] = fImgRotSym(img,pvt,horOS,rotAgl,varargin)%% image rotation and symmetrization (for FROG)%% symLeft: Symmetrized left side of the image%% img: input image% pvt: pivot pixel [x,y]% horOS: horizontal offset [pixel]% rotAgl: rotation angle [deg]% varagin {1}: figure handle for figure on%% Written by Kei Nakamura% % 2014/4/7 ver.1: Created % 2014/8/1 ver.1.1: figure handle in varargin% 2015/6/16 ver.1.2: angle and axis scan%% used in% bellaFrogFitTest% bellaFrogSSFitV01%%% main bodyimgSize = size(img);    % image row and column (flipped)% search for optsrch = ~isempty(varargin{1});   % logic for checkingif nargin==5&&~isempty(varargin{1})&&srch == 1;    imgThre = 10;   % image threshold    nmbAgl = 200;   % number of angle    aglSwing = 2;   % +/- swing deg    nmbOS = 7;    % number of offset    horOSS = [horOS-floor(nmbOS/2):horOS-floor(nmbOS/2)+nmbOS-1];    rotAglS = linspace(rotAgl-aglSwing,rotAgl+aglSwing,nmbAgl);    imgStd = zeros(nmbAgl,nmbOS);        for jj=1:nmbAgl        for kk=1:nmbOS            prcImg = fImageRotV02(img,rotAglS(jj),pvt);  % rotate aling pivot            xWidth = 0.5*imgSize(2) - abs(horOSS(kk));   % width of half box            if horOSS(kk)~=0                pad = zeros(imgSize(1),abs(horOSS(kk))); % for padding                if horOSS(kk)>0                    remain = prcImg(:,horOSS(kk)+1:2*horOSS(kk));                    leftHlf = prcImg(:,2*horOSS(kk)+1:2*horOSS(kk)+xWidth);                    rightHlf = prcImg(:,2*horOSS(kk)+xWidth+1:end);                    leftHlf(:,:) = 0.5*(leftHlf+fliplr(rightHlf));   % symmetrize left                    symImg = [remain,leftHlf,fliplr(leftHlf),pad];  % symmetric image                    %symLeft = [remain,leftHlf];  % symmetric left                else                    leftHlf = prcImg(:,1:xWidth);                    rightHlf = prcImg(:,xWidth+1:2*xWidth);                    remain = prcImg(:,2*xWidth+1:2*xWidth+abs(horOSS(kk)));                    leftHlf(:,:) = 0.5*(leftHlf+fliplr(rightHlf));   % symmetric left                    symImg = [pad,leftHlf,fliplr(leftHlf),remain];                    %symLeft = fliplr([fliplr(leftHlf),remain]);  % symmetric left                end            else                leftHlf = prcImg(:,1:xWidth);                rightHlf = prcImg(:,xWidth+1:end);                symLeft = 0.5*(leftHlf+fliplr(rightHlf));  % symmetric left                symImg = [symLeft,fliplr(symLeft)];            end            symImg = symImg.*(symImg>imgThre);  % threshold            tmDmain = sum(symImg); % time domain            imgStd(jj,kk) = fGetRmsV01(1:imgSize(2),tmDmain);   % std in time        end    end    figure(11)%     subplot(1,3,1)%     pcolor(symImg)%     shading interp%     subplot(1,3,2)%     plot(tmDmain)%     subplot(1,3,3)    subplot(1,2,1)    pcolor(horOSS,rotAglS,imgStd)    shading interp    colormap jet    colorbar    title(num2str(horOS))        pp = find(horOSS==horOS);    subplot(1,2,2)    plot(rotAglS,imgStd(:,pp),'o')    title(horOSS(pp))end% rotate image% figure(11)% pcolor(img)% shading interpprcImg = fImageRotV02(img,rotAgl,pvt);  % rotate aling pivot% symmetrizationxWidth = 0.5*imgSize(2) - abs(horOS);   % width of half boxif horOS~=0    pad = zeros(imgSize(1),abs(horOS)); % for padding    if horOS>0        remain = prcImg(:,horOS+1:2*horOS);        leftHlf = prcImg(:,2*horOS+1:2*horOS+xWidth);        rightHlf = prcImg(:,2*horOS+xWidth+1:end);        leftHlf(:,:) = 0.5*(leftHlf+fliplr(rightHlf));   % symmetrize left        symImg = [remain,leftHlf,fliplr(leftHlf),pad];  % symmetric image        symLeft = [remain,leftHlf];  % symmetric left    else        leftHlf = prcImg(:,1:xWidth);        rightHlf = prcImg(:,xWidth+1:2*xWidth);        remain = prcImg(:,2*xWidth+1:2*xWidth+abs(horOS));        leftHlf(:,:) = 0.5*(leftHlf+fliplr(rightHlf));   % symmetric left        symImg = [pad,leftHlf,fliplr(leftHlf),remain];        symLeft = fliplr([fliplr(leftHlf),remain]);  % symmetric left    endelse    leftHlf = prcImg(:,1:xWidth);    rightHlf = prcImg(:,xWidth+1:end);    symLeft = 0.5*(leftHlf+fliplr(rightHlf));  % symmetric left    symImg = [symLeft,fliplr(symLeft)];end        %% plot for checkingline1 = fPa2Line(pvt,atan(rotAgl*pi/180));line2 = fPa2Line(pvt,-1/line1(1));if nargin==5&&~isempty(varargin{1})    set(0,'CurrentFigure',varargin{1})        subplot(2,3,1)    pcolor(1:imgSize(2),1:imgSize(1),img)    shading interp    colormap jet    cax = caxis;    caxis([0 cax(2)])    colorbar        hold on    plot(1:imgSize(2),polyval(line1,[1:imgSize(2)]),'w--')    plot(1:imgSize(2),polyval(line2,[1:imgSize(2)]),'w--')    hold off    title('input image')    xlabel('pixel')    ylabel('pixel')    subplot(2,3,2)    pcolor(1:imgSize(2),1:imgSize(1),prcImg)    shading interp    colormap jet    cax = caxis;    caxis([0 cax(2)])    colorbar    hold on    plot([pvt(1) pvt(1)],[1 imgSize(1)],'w--')    plot([0.5*imgSize(2) 0.5*imgSize(2)],[1 imgSize(1)],'w-')    plot([pvt(1)+0.2*imgSize(2) pvt(1)+0.2*imgSize(2)],[1 imgSize(1)],'g--')    plot([pvt(1)-0.2*imgSize(2) pvt(1)-0.2*imgSize(2)],[1 imgSize(1)],'g--')    plot([1 imgSize(2)],[pvt(2) pvt(2)],'w-')    plot([1 imgSize(2)],[pvt(2)+0.2*imgSize(1) pvt(2)+0.2*imgSize(1)],'g--')    plot([1 imgSize(2)],[pvt(2)-0.2*imgSize(1) pvt(2)-0.2*imgSize(1)],'g--')    hold off    title('rotated image')    xlabel('pixel')    ylabel('pixel')    subplot(2,3,3)    pcolor(1:imgSize(2),1:imgSize(1),symImg)    shading interp    colormap jet    cax = caxis;    caxis([0 cax(2)])    colorbar    hold on    plot([0.5*imgSize(2) 0.5*imgSize(2)],[1 imgSize(1)],'w-')    plot([1 imgSize(2)],[pvt(2) pvt(2)],'w-')    hold off    title('symmetrized image')    xlabel('pixel')    ylabel('pixel')        subplot(2,3,4)    pcolor(1:imgSize(2),1:imgSize(1),log10(img))    shading interp    colormap jet    cax = caxis;    caxis([0 cax(2)])    colorbar        hold on    plot(1:imgSize(2),polyval(line1,[1:imgSize(2)]),'w--')    plot(1:imgSize(2),polyval(line2,[1:imgSize(2)]),'w--')    hold off    title('input image')    xlabel('pixel')    ylabel('pixel')    subplot(2,3,5)    pcolor(1:imgSize(2),1:imgSize(1),log10(prcImg))    shading interp    colormap jet    cax = caxis;    caxis([0 cax(2)])    colorbar    hold on    plot([pvt(1) pvt(1)],[1 imgSize(1)],'w--')    plot([0.5*imgSize(2) 0.5*imgSize(2)],[1 imgSize(1)],'w-')    plot([pvt(1)+0.2*imgSize(2) pvt(1)+0.2*imgSize(2)],[1 imgSize(1)],'g--')    plot([pvt(1)-0.2*imgSize(2) pvt(1)-0.2*imgSize(2)],[1 imgSize(1)],'g--')    plot([1 imgSize(2)],[pvt(2) pvt(2)],'w-')    plot([1 imgSize(2)],[pvt(2)+0.2*imgSize(1) pvt(2)+0.2*imgSize(1)],'g--')    plot([1 imgSize(2)],[pvt(2)-0.2*imgSize(1) pvt(2)-0.2*imgSize(1)],'g--')    hold off    title('rotated image')    xlabel('pixel')    ylabel('pixel')    subplot(2,3,6)    pcolor(1:imgSize(2),1:imgSize(1),log10(symImg))    shading interp    colormap jet    cax = caxis;    caxis([0 cax(2)])    colorbar    hold on    plot([0.5*imgSize(2) 0.5*imgSize(2)],[1 imgSize(1)],'w-')    plot([abs(horOS) abs(horOS)],[1 imgSize(1)],'w-')    plot([1 imgSize(2)],[pvt(2) pvt(2)],'w-')    hold off    title('symmetrized image')    xlabel('pixel')    ylabel('pixel')end
